import { Component, OnInit } from '@angular/core';
import { Router, ActivatedRoute } from '@angular/router';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { first } from 'rxjs/operators';
import { EmployeeService, DepartmentService, AlertService } from '@app/_services';
import { Department } from '@app/_models';

@Component({
    templateUrl: 'add-edit.component.html',
    standalone: false
})
export class AddEditComponent implements OnInit {
    form!: FormGroup;
    empId?: string;
    title!: string;
    loading = false;
    submitting = false;
    submitted = false;
    departments: Department[] = [];

    constructor(
        private formBuilder: FormBuilder,
        private route: ActivatedRoute,
        private router: Router,
        private employeeService: EmployeeService,
        private departmentService: DepartmentService,
        private alertService: AlertService
    ) {}

    ngOnInit() {
        this.empId = this.route.snapshot.params['id'];
        this.title = this.empId ? 'Edit Employee Record' : 'Add Employee Record';

        this.form = this.formBuilder.group({
            empId: ['', Validators.required],
            email: ['', [Validators.required, Validators.email]],
            firstName: ['', Validators.required],
            lastName: ['', Validators.required],
            position: ['', Validators.required],
            department: ['', Validators.required],
            hireDate: ['', Validators.required]
        });

        // Load departments list for dropdown selection
        this.departmentService.getAll()
            .pipe(first())
            .subscribe(depts => this.departments = depts);

        if (this.empId) {
            this.loading = true;
            this.form.get('empId')?.disable(); // empId is primaryKey and can't be changed
            this.employeeService.getById(this.empId)
                .pipe(first())
                .subscribe({
                    next: emp => {
                        this.form.patchValue(emp);
                        this.loading = false;
                    },
                    error: error => {
                        this.alertService.error(error);
                        this.loading = false;
                    }
                });
        }
    }

    get f() { return this.form.controls; }

    onSubmit() {
        this.submitted = true;
        this.alertService.clear();

        if (this.form.invalid) return;

        this.submitting = true;

        // Include empId in body even if form field is disabled
        const data = this.form.getRawValue();

        const saveObservable = this.empId
            ? this.employeeService.update(this.empId, data)
            : this.employeeService.create(data);

        saveObservable
            .pipe(first())
            .subscribe({
                next: () => {
                    this.alertService.success('Employee record saved successfully', { keepAfterRouteChange: true });
                    this.router.navigate(['../../'], { relativeTo: this.route });
                },
                error: error => {
                    this.alertService.error(error);
                    this.submitting = false;
                }
            });
    }
}
<h2 class="page-title mb-4">{{title}}</h2>

<div class="card">
    <div class="card-body">
        <form *ngIf="!loading" [formGroup]="form" (ngSubmit)="onSubmit()">
            <div class="row">
                <div class="mb-3 col-md-4">
                    <label class="form-label">Employee ID</label>
                    <input type="text" formControlName="empId" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['empId'].errors }" placeholder="e.g. EMP001" />
                    <div *ngIf="submitted && f['empId'].errors" class="invalid-feedback">
                        <div *ngIf="f['empId'].errors['required']">Employee ID is required</div>
                    </div>
                </div>

                <div class="mb-3 col-md-8">
                    <label class="form-label">Associated User Email</label>
                    <input type="email" formControlName="email" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['email'].errors }" placeholder="must belong to a registered account" />
                    <div *ngIf="submitted && f['email'].errors" class="invalid-feedback">
                        <div *ngIf="f['email'].errors['required']">Email is required</div>
                        <div *ngIf="f['email'].errors['email']">Must be a valid email</div>
                    </div>
                </div>
            </div>

            <div class="row">
                <div class="mb-3 col-md-6">
                    <label class="form-label">First Name</label>
                    <input type="text" formControlName="firstName" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['firstName'].errors }" />
                    <div *ngIf="submitted && f['firstName'].errors" class="invalid-feedback">
                        <div *ngIf="f['firstName'].errors['required']">First Name is required</div>
                    </div>
                </div>
                <div class="mb-3 col-md-6">
                    <label class="form-label">Last Name</label>
                    <input type="text" formControlName="lastName" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['lastName'].errors }" />
                    <div *ngIf="submitted && f['lastName'].errors" class="invalid-feedback">
                        <div *ngIf="f['lastName'].errors['required']">Last Name is required</div>
                    </div>
                </div>
            </div>

            <div class="row">
                <div class="mb-3 col-md-6">
                    <label class="form-label">Position / Job Title</label>
                    <input type="text" formControlName="position" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['position'].errors }" placeholder="e.g. Senior Software Architect" />
                    <div *ngIf="submitted && f['position'].errors" class="invalid-feedback">
                        <div *ngIf="f['position'].errors['required']">Position is required</div>
                    </div>
                </div>

                <div class="mb-3 col-md-6">
                    <label class="form-label">Department</label>
                    <select formControlName="department" class="form-select" [ngClass]="{ 'is-invalid': submitted && f['department'].errors }">
                        <option value=""></option>
                        <option *ngFor="let dept of departments" [value]="dept.name">{{dept.name}}</option>
                    </select>
                    <div *ngIf="submitted && f['department'].errors" class="invalid-feedback">
                        <div *ngIf="f['department'].errors['required']">Department is required</div>
                    </div>
                </div>
            </div>

            <div class="row mb-4">
                <div class="mb-3 col-md-6">
                    <label class="form-label">Hire Date</label>
                    <input type="date" formControlName="hireDate" class="form-control" [ngClass]="{ 'is-invalid': submitted && f['hireDate'].errors }" />
                    <div *ngIf="submitted && f['hireDate'].errors" class="invalid-feedback">
                        <div *ngIf="f['hireDate'].errors['required']">Hire Date is required</div>
                    </div>
                </div>
            </div>

            <div>
                <button [disabled]="submitting" class="btn btn-primary me-2">
                    <span *ngIf="submitting" class="spinner-border spinner-border-sm me-1"></span>
                    Save Record
                </button>
                <a routerLink="../../" class="btn btn-link">Cancel</a>
            </div>
        </form>

        <div *ngIf="loading" class="text-center p-4">
            <span class="spinner-border spinner-border-lg text-primary"></span>
        </div>
    </div>
</div>
